-- Donnees generees automatiquement par tools/build_recommendation_data.php
-- Executer apres database/migrations/001_recommendation_engine.sql
SET NAMES utf8mb4;
START TRANSACTION;
DELETE FROM recommendation_links WHERE source IN ('historical', 'generated');
DELETE FROM recommendation_sequence_contents WHERE source IN ('historical', 'generated');
DELETE FROM recommendation_contents WHERE source IN ('historical', 'generated');
DROP TEMPORARY TABLE IF EXISTS recommendation_import_rows;
CREATE TEMPORARY TABLE recommendation_import_rows (
 sequence_id INT NOT NULL, filiere VARCHAR(255) NOT NULL, unite_id INT NOT NULL,
 objectif TEXT NOT NULL, objectif_hash CHAR(64) NOT NULL, description TEXT NOT NULL, description_hash CHAR(64) NOT NULL,
 observation TEXT NOT NULL, observation_hash CHAR(64) NOT NULL, disposition TEXT NOT NULL, disposition_hash CHAR(64) NOT NULL,
 source ENUM('historical','generated') NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

SELECT 'objectif', MIN(objectif), MIN(objectif), objectif_hash,
       IF(SUM(source = 'historical') > 0, 'historical', 'generated'), COUNT(*)
FROM recommendation_import_rows
GROUP BY objectif_hash;

SELECT 'description', MIN(description), MIN(description), description_hash,
       IF(SUM(source = 'historical') > 0, 'historical', 'generated'), COUNT(*)
FROM recommendation_import_rows
GROUP BY description_hash;

SELECT 'observation', MIN(observation), MIN(observation), observation_hash,
       IF(SUM(source = 'historical') > 0, 'historical', 'generated'), COUNT(*)
FROM recommendation_import_rows
GROUP BY observation_hash;

SELECT 'disposition', MIN(disposition), MIN(disposition), disposition_hash,
       IF(SUM(source = 'historical') > 0, 'historical', 'generated'), COUNT(*)
FROM recommendation_import_rows
GROUP BY disposition_hash;

SELECT expanded.sequence_id, contents.id, expanded.source, expanded.occurrences,
       IF(expanded.source = 'historical', 1.0000, 0.6500)
FROM (SELECT sequence_id, 'objectif' AS content_type, objectif_hash AS content_hash,
        IF(SUM(source = 'historical') > 0, 'historical', 'generated') AS source, COUNT(*) AS occurrences
        FROM recommendation_import_rows GROUP BY sequence_id, objectif_hash
 UNION ALL 
SELECT sequence_id, 'description' AS content_type, description_hash AS content_hash,
        IF(SUM(source = 'historical') > 0, 'historical', 'generated') AS source, COUNT(*) AS occurrences
        FROM recommendation_import_rows GROUP BY sequence_id, description_hash
 UNION ALL 
SELECT sequence_id, 'observation' AS content_type, observation_hash AS content_hash,
        IF(SUM(source = 'historical') > 0, 'historical', 'generated') AS source, COUNT(*) AS occurrences
        FROM recommendation_import_rows GROUP BY sequence_id, observation_hash
 UNION ALL 
SELECT sequence_id, 'disposition' AS content_type, disposition_hash AS content_hash,
        IF(SUM(source = 'historical') > 0, 'historical', 'generated') AS source, COUNT(*) AS occurrences
        FROM recommendation_import_rows GROUP BY sequence_id, disposition_hash) expanded
INNER JOIN recommendation_contents contents
    ON contents.content_type = expanded.content_type
   AND contents.normalized_hash = expanded.content_hash;

SELECT r.sequence_id, parent.id, child.id, COUNT(*),
         IF(SUM(r.source = 'historical') > 0, 1.0000, 0.6500),
         IF(SUM(r.source = 'historical') > 0, 'historical', 'generated')
FROM recommendation_import_rows AS r
INNER JOIN recommendation_contents parent
    ON parent.content_type = 'objectif'
    AND parent.normalized_hash = r.objectif_hash
INNER JOIN recommendation_contents child
    ON child.content_type = 'description'
    AND child.normalized_hash = r.description_hash
GROUP BY r.sequence_id, parent.id, child.id;

SELECT r.sequence_id, parent.id, child.id, COUNT(*),
         IF(SUM(r.source = 'historical') > 0, 1.0000, 0.6500),
         IF(SUM(r.source = 'historical') > 0, 'historical', 'generated')
FROM recommendation_import_rows AS r
INNER JOIN recommendation_contents parent
    ON parent.content_type = 'description'
    AND parent.normalized_hash = r.description_hash
INNER JOIN recommendation_contents child
    ON child.content_type = 'observation'
    AND child.normalized_hash = r.observation_hash
GROUP BY r.sequence_id, parent.id, child.id;

SELECT r.sequence_id, parent.id, child.id, COUNT(*),
         IF(SUM(r.source = 'historical') > 0, 1.0000, 0.6500),
         IF(SUM(r.source = 'historical') > 0, 'historical', 'generated')
FROM recommendation_import_rows AS r
INNER JOIN recommendation_contents parent
    ON parent.content_type = 'observation'
    AND parent.normalized_hash = r.observation_hash
INNER JOIN recommendation_contents child
    ON child.content_type = 'disposition'
    AND child.normalized_hash = r.disposition_hash
GROUP BY r.sequence_id, parent.id, child.id;
VALUES ('CSV historiques consolides', 'd955893217cbcf014b0a3f3b3a72c5da3b8e03f0314558e6d478cda419fe9b53', 1298, 0, 'completed', '{"sources":["suivi pédagogique(Développement informatique).csv","suivi pédagogique(Gestion des entreprises).csv","suivi pédagogique(Infographiste).csv"],"generated_rows":20}', NOW())
ON DUPLICATE KEY UPDATE imported_rows = VALUES(imported_rows), rejected_rows = VALUES(rejected_rows),
status = 'completed', details = VALUES(details), completed_at = NOW();
DROP TEMPORARY TABLE recommendation_import_rows;
COMMIT;
